24.         protected override void OnModelCreating(ModelBuilder modelBuilder)
25.         {
26.             // Configure all DateTime properties to use datetime2
27.             foreach (var entityType in modelBuilder.Model.GetEntityTypes())
28.             {
29.                 var properties = entityType.ClrType.GetProperties()
30.                     .Where(p => p.PropertyType == typeof(DateTime) || p.PropertyType == typeof(DateTime?));
31. 
32.                 foreach (var property in properties)
33.                 {
34.                     modelBuilder.Entity(entityType.ClrType)
35.                         .Property(property.Name)
36.                         .HasColumnType("datetime2");
37.                 }
38.             }
