using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public class PersonTests
    {
        [TestMethod]
        public void FullName_WithLastAndFirstName_ReturnsCommaSeparatedFormat()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            Assert.AreEqual("Smith, John", student.FullName);
        }

        [TestMethod]
        [DataRow("Doe", "Jane", "Doe, Jane")]
        [DataRow("O'Brien", "Patrick", "O'Brien, Patrick")]
        [DataRow("Kim", "A", "Kim, A")]
        public void FullName_VariousNames_ReturnsCorrectFormat(string lastName, string firstName, string expected)
        {
            var person = new Instructor { LastName = lastName, FirstMidName = firstName };
            Assert.AreEqual(expected, person.FullName);
        }

        [TestMethod]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = DateTime.Parse("2023-09-01");
            var student = new Student { EnrollmentDate = date };
            Assert.AreEqual(date, student.EnrollmentDate);
        }

        [TestMethod]
        public void Student_Enrollments_DefaultsToNull()
        {
            var student = new Student();
            Assert.IsNull(student.Enrollments);
        }

        [TestMethod]
        public void Instructor_HireDate_CanBeSet()
        {
            var date = DateTime.Parse("2000-01-15");
            var instructor = new Instructor { HireDate = date };
            Assert.AreEqual(date, instructor.HireDate);
        }

        [TestMethod]
        public void Instructor_CourseAssignments_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.IsNull(instructor.CourseAssignments);
        }

        [TestMethod]
        public void Instructor_OfficeAssignment_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.IsNull(instructor.OfficeAssignment);
        }

        [TestMethod]
        public void Person_ID_DefaultsToZero()
        {
            var student = new Student();
            Assert.AreEqual(0, student.ID);
        }

        [TestMethod]
        public void Person_ID_CanBeSet()
        {
            var student = new Student { ID = 42 };
            Assert.AreEqual(42, student.ID);
        }
    }
}

