namespace ContosoUniversity.Tests
{
    [TestClass]
    public class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 2, 3);
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 1, 3);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        }

        [TestMethod]
        [DataRow(10, 5, 2)]
        [DataRow(10, 3, 4)]
        [DataRow(1, 10, 1)]
        [DataRow(0, 10, 0)]
        [DataRow(15, 5, 3)]
        [DataRow(16, 5, 4)]
        public void Constructor_CalculatesTotalPages_Various(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 1, 5);
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        public void HasPreviousPage_OnFirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_OnSecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5); // 2 pages, on page 2
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_OnFirstPage_WithMorePages_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5); // 2 pages, on page 1
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5); // 1 page total
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageOfData()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);  // First item on page 2
            Assert.AreEqual(10, result[4]); // Last item on page 2
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.IsTrue(result.HasNextPage);
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5); // 3 pages, last page has 2 items

            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
