        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course", notification.EntityType);
            Assert.AreEqual("1050", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNotNull(notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "User");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "5", "John Doe", EntityOperation.UPDATE, "User");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student 'John Doe' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE, "User");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "1050", EntityOperation.CREATE, "User");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course (ID: 1050) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_DequeuesInFIFOOrder()
        {
            _service.SendNotification("Course", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
            _service.SendNotification("Course", "3", "Third", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();
            var fourth = _service.ReceiveNotification();

            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("2", second.EntityId);
            Assert.AreEqual("3", third.EntityId);
            Assert.IsNull(fourth);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
