            Assert.AreEqual("Instructor", notification.EntityType);
            Assert.AreEqual("10", notification.EntityId);
            Assert.AreEqual("UPDATE", notification.Operation);
        }

        [TestMethod]
        public void SendNotification_MultipleNotifications_AllQueued()
        {
