        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);
            Assert.AreEqual(11, context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_DatabaseAlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestHelper.CreateInMemoryContext();

            // First initialization
            DbInitializer.Initialize(context);
            var studentCountAfterFirst = context.Students.Count();

            // Second initialization - should return early
            DbInitializer.Initialize(context);
            var studentCountAfterSecond = context.Students.Count();

            Assert.AreEqual(studentCountAfterFirst, studentCountAfterSecond);
        }

        [TestMethod]
        public void Initialize_VerifiesStudentNames()
        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alexander" && s.FirstMidName == "Carson"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alonso" && s.FirstMidName == "Meredith"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Olivetto" && s.FirstMidName == "Nino"));
        }

        [TestMethod]
        public void Initialize_VerifiesInstructorNames()
        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Abercrombie" && i.FirstMidName == "Kim"));
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Fakhouri" && i.FirstMidName == "Fadi"));
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Zheng" && i.FirstMidName == "Roger"));
        }

        [TestMethod]
        public void Initialize_VerifiesDepartmentNames()
        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Departments.Any(d => d.Name == "English"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Mathematics"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Engineering"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Economics"));
        }

        [TestMethod]
        public void Initialize_VerifiesCourseTitles()
        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            Assert.IsTrue(context.Courses.Any(c => c.Title == "Chemistry" && c.CourseID == 1050));
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Calculus" && c.CourseID == 1045));
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Literature" && c.CourseID == 2042));
        }

        [TestMethod]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            var departments = context.Departments.ToList();
            Assert.IsTrue(departments.All(d => d.InstructorID != null));
        }

        [TestMethod]
        public void Initialize_EnrollmentsHaveGrades()
        {
            using var context = TestHelper.CreateInMemoryContext();
            DbInitializer.Initialize(context);

            var enrollments = context.Enrollments.ToList();
            // Some enrollments have grades, some don't (Anand's Chemistry has no grade)
            Assert.IsTrue(enrollments.Any(e => e.Grade != null));
            Assert.IsTrue(enrollments.Any(e => e.Grade == null));
        }

        [TestMethod]
        public void Initialize_CalledTwice_EnrollmentsNotDuplicated()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);
            var countBefore = context.Enrollments.Count();

            // The guard only checks Students, so enrollment duplication is prevented
            // by the early return when students exist
            DbInitializer.Initialize(context);
            var countAfter = context.Enrollments.Count();

            Assert.AreEqual(countBefore, countAfter);
        }
    }
}

