+    {
+        private NotificationService _service;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            _service = new NotificationService();
+            // Drain the static queue to ensure test isolation
+            while (_service.ReceiveNotification() != null) { }
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            _service?.Dispose();
+        }
+
+        [TestMethod]
+        public void SendNotification_WithDisplayName_CreatesCorrectNotification()
+        {
+            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "Admin");
+
+            var notification = _service.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Course", notification.EntityType);
+            Assert.AreEqual("1050", notification.EntityId);
+            Assert.AreEqual("CREATE", notification.Operation);
+            Assert.AreEqual("Admin", notification.CreatedBy);
+            Assert.IsFalse(notification.IsRead);
+            Assert.IsNotNull(notification.Message);
+        }
+
+        [TestMethod]
+        public void SendNotification_WithoutUserName_DefaultsToSystem()
+        {
+            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);
+
+            var notification = _service.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
+        {
+            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "User");
+
