using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_NoStudents_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithStudents_ReturnsGroupedData()
        {
            // Seed students with different enrollment dates
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "Student1", EnrollmentDate = DateTime.Parse("2023-09-01") },
                new Student { FirstMidName = "B", LastName = "Student2", EnrollmentDate = DateTime.Parse("2023-09-01") },
                new Student { FirstMidName = "C", LastName = "Student3", EnrollmentDate = DateTime.Parse("2024-01-15") }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count); // Two distinct enrollment dates

            var sept2023Group = model.FirstOrDefault(g => g.EnrollmentDate == DateTime.Parse("2023-09-01"));
            Assert.IsNotNull(sept2023Group);
            Assert.AreEqual(2, sept2023Group.StudentCount);

            var jan2024Group = model.FirstOrDefault(g => g.EnrollmentDate == DateTime.Parse("2024-01-15"));
            Assert.IsNotNull(jan2024Group);
            Assert.AreEqual(1, jan2024Group.StudentCount);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            var result = _controller.Contact() as ViewResult;
            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;
            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new StudentsController(_context);

            // Seed test students
            _context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") }
            );
            _context.SaveChanges();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index Tests ---

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
