using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);

            // Drain the static notification queue for test isolation
            var drainService = new NotificationService();
            TestHelper.DrainNotificationQueue(drainService);
            drainService.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications() as JsonResult;
            Assert.IsNotNull(result);

            dynamic value = result.Value;
            Assert.IsNotNull(value);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Pre-populate the static queue
            var tempService = new NotificationService();
            tempService.SendNotification("Course", "1", "Chemistry", EntityOperation.CREATE, "Admin");
            tempService.SendNotification("Student", "2", "John Doe", EntityOperation.UPDATE, "Admin");
            tempService.Dispose();

            var result = _controller.GetNotifications() as JsonResult;
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10Notifications()
        {
            // Pre-populate queue with more than 10 notifications
            var tempService = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                tempService.SendNotification("Entity", i.ToString(), $"Entity{i}", EntityOperation.CREATE);
            }
            tempService.Dispose();

            var result = _controller.GetNotifications() as JsonResult;
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
            // The controller limits to 10 notifications per request
        }

        [TestMethod]
        public void MarkAsRead_ValidId_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void MarkAsRead_InvalidId_StillReturnsSuccess()
        {
            // MarkAsRead is a no-op, so any ID should succeed
            var result = _controller.MarkAsRead(-1) as JsonResult;
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }
    }
}

